/* ============================================
 *    AAP DESIGN SYSTEM v2.0  Premium Refinement
 *    ============================================ */

/* --- DESIGN TOKENS --- */
:root {
	  --aap-navy: #0d1f3c;
	  --aap-blue: #1a56db;
	  --aap-blue-hover: #1648c0;
	  --aap-blue-light: #e8f0fe;
	  --aap-blue-mid: #dbeafe;
	  --aap-accent: #0ea5e9;
	  --aap-teal: #0891b2;
	  --aap-white: #ffffff;
	  --aap-off-white: #f8fafc;
	  --aap-gray-50: #f1f5f9;
	  --aap-gray-100: #e2e8f0;
	  --aap-gray-200: #cbd5e1;
	  --aap-gray-600: #475569;
	  --aap-gray-700: #334155;
	  --aap-gray-800: #1e293b;
	  --aap-body: #1e293b;
	  --aap-heading: #0d1f3c;
	  --aap-radius: 12px;
	  --aap-radius-lg: 20px;
	  --aap-shadow: 0 4px 20px rgba(13,31,60,0.08);
	  --aap-shadow-md: 0 8px 32px rgba(13,31,60,0.12);
	  --aap-shadow-lg: 0 16px 48px rgba(13,31,60,0.16);
	  --aap-transition: all 0.25s cubic-bezier(0.4,0,0.2,1);
	  --aap-font-sans: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

/* --- GOOGLE FONT IMPORT --- */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&amp;display=swap');

/* --- BASE BODY --- */
body {
	  font-family: var(--aap-font-sans) !important;
	  color: var(--aap-body) !important;
	  background: #ffffff !important;
	  -webkit-font-smoothing: antialiased;
}

/* --- HIDE OLD "HOME" PAGE TITLE --- */
.entry-header .entry-title,
.page .page-title-entry-header,
h1.page-title {
	  display: none !important;
}

/* Hide H1 "Home" literal title on homepage */
.home .entry-header { display: none !important; }

/* --- GLOBAL HEADINGS --- */
h1, h2, h3, h4, h5, h6,
.nv-title, .entry-title {
	  font-family: var(--aap-font-sans) !important;
	  color: var(--aap-heading) !important;
	  font-weight: 700 !important;
	  line-height: 1.2 !important;
	  letter-spacing: -0.02em;
}

/* --- GLOBAL PARAGRAPHS --- */
p, li, label {
	  font-family: var(--aap-font-sans) !important;
	  color: var(--aap-body) !important;
	  line-height: 1.75 !important;
	  font-size: 1rem;
}

/* ============================================
 *    HEADER  Premium Sticky Bar
 *    ============================================ */
.header-wrapper,
#header-wrapper,
.hfg-header,
.nv-navbar,
header.site-header,
.site-header {
	  background: var(--aap-white) !important;
	  border-bottom: 1px solid var(--aap-gray-100) !important;
	  box-shadow: 0 2px 16px rgba(13,31,60,0.06) !important;
	  position: sticky !important;
	  top: 0 !important;
	  z-index: 9999 !important;
}

/* Logo text treatment */
.site-logo a,
.custom-logo-link,
.navbar-brand,
.header-logo-link,
.nv-title a,
.site-title a,
.site-branding a {
	  font-family: var(--aap-font-sans) !important;
	  font-size: 1.35rem !important;
	  font-weight: 800 !important;
	  color: var(--aap-navy) !important;
	  text-decoration: none !important;
	  letter-spacing: -0.02em;
}

/* Nav links */
.primary-menu-ul li a,
.header-menu li a,
#main-nav li a,
nav.primary-nav ul li a,
.nv-nav-wrap li a {
	  font-family: var(--aap-font-sans) !important;
	  font-size: 0.875rem !important;
	  font-weight: 500 !important;
	  color: var(--aap-gray-700) !important;
	  text-decoration: none !important;
	  padding: 8px 14px !important;
	  border-radius: 8px !important;
	  transition: var(--aap-transition) !important;
}
.primary-menu-ul li a:hover,
.header-menu li a:hover,
.nv-nav-wrap li a:hover {
	  color: var(--aap-blue) !important;
	  background: var(--aap-blue-mid) !important;
}

/* "Call Now" header button */
a[href*="tel"],
.header-cta a,
.call-now-btn,
header a[href^="tel"] {
	  background: var(--aap-blue) !important;
	  color: var(--aap-white) !important;
	  padding: 9px 20px !important;
	  border-radius: 8px !important;
	  font-weight: 600 !important;
	  font-size: 0.875rem !important;
	  text-decoration: none !important;
	  transition: var(--aap-transition) !important;
	  border: none !important;
}
a[href*="tel"]:hover,
header a[href^="tel"]:hover {
	  background: var(--aap-blue-hover) !important;
	  transform: translateY(-1px) !important;
	  box-shadow: 0 4px 12px rgba(26,86,219,0.3) !important;
}

/* ============================================
 *    GLOBAL BUTTONS
 *    ============================================ */
.wp-block-button__link,
.wp-element-button,
a.wp-block-button__link,
.nv-btn,
.btn-primary,
.aap-btn,
input[type="submit"],
button[type="submit"],
.wpforms-submit {
	  background: var(--aap-blue) !important;
	  color: var(--aap-white) !important;
	  padding: 13px 28px !important;
	  border-radius: 10px !important;
	  font-family: var(--aap-font-sans) !important;
	  font-weight: 600 !important;
	  font-size: 0.95rem !important;
	  text-decoration: none !important;
	  border: none !important;
	  cursor: pointer !important;
	  transition: var(--aap-transition) !important;
	  box-shadow: 0 4px 14px rgba(26,86,219,0.25) !important;
	  display: inline-block !important;
}
.wp-block-button__link:hover,
.aap-btn:hover,
input[type="submit"]:hover,
.wpforms-submit:hover {
	  background: var(--aap-blue-hover) !important;
	  transform: translateY(-2px) !important;
	  box-shadow: 0 8px 20px rgba(26,86,219,0.35) !important;
	  color: var(--aap-white) !important;
}

/* Outline / ghost button variant */
.wp-block-button.is-style-outline .wp-block-button__link,
.aap-btn-ghost {
	  background: transparent !important;
	  color: var(--aap-blue) !important;
	  border: 2px solid var(--aap-blue) !important;
	  box-shadow: none !important;
}
.wp-block-button.is-style-outline .wp-block-button__link:hover,
.aap-btn-ghost:hover {
	  background: var(--aap-blue) !important;
	  color: var(--aap-white) !important;
	  transform: translateY(-2px) !important;
}

/* ============================================
 *    SECTION WRAPPERS — layout system
 *    ============================================ */
.aap-section { padding: 80px 0; }
.aap-section-sm { padding: 48px 0; }
.aap-container {
	  max-width: 1200px;
	  margin: 0 auto;
	  padding: 0 32px;
}

/* Section backgrounds */
.aap-bg-navy { background: var(--aap-navy) !important; }
.aap-bg-navy * { color: var(--aap-white) !important; }
.aap-bg-blue-light { background: var(--aap-blue-light) !important; }
.aap-bg-gray { background: var(--aap-gray-50) !important; }
.aap-bg-white { background: var(--aap-white) !important; }

/* Section labels (eyebrow) */
.aap-label,
.wp-block-group .aap-label,
[class*="nv-page-"] .has-text-align-left + p {
	  display: inline-block;
	  font-size: 0.75rem !important;
	  font-weight: 700 !important;
	  letter-spacing: 0.1em !important;
	  text-transform: uppercase !important;
	  color: var(--aap-blue) !important;
	  background: var(--aap-blue-light) !important;
	  padding: 4px 12px !important;
	  border-radius: 100px !important;
	  margin-bottom: 16px !important;
}

/* ============================================
 *    CARDS  Floating premium style
 *    ============================================ */
.wp-block-column,
.aap-card,
.nv-card {
	  background: var(--aap-white) !important;
	  border-radius: var(--aap-radius-lg) !important;
	  box-shadow: var(--aap-shadow) !important;
	  padding: 32px !important;
	  border: 1px solid var(--aap-gray-100) !important;
	  transition: var(--aap-transition) !important;
}
.wp-block-column:hover,
.aap-card:hover {
	  transform: translateY(-4px) !important;
	  box-shadow: var(--aap-shadow-md) !important;
	  border-color: var(--aap-blue-mid) !important;
}

/* ============================================
 *    HERO SECTION
 *    ============================================ */
.aap-hero,
.wp-block-cover.aap-hero,
.home-hero-section {
	  background: linear-gradient(135deg, #0d1f3c 0%, #1a3a6b 60%, #1a56db 100%) !important;
	  padding: 100px 0 80px !important;
	  position: relative;
	  overflow: hidden;
}
.aap-hero::before {
	  content: '';
	  position: absolute;
	  top: -40%;
	  right: -10%;
	  width: 60%;
	  height: 150%;
	  background: radial-gradient(circle, rgba(26,86,219,0.15) 0%, transparent 70%);
	  pointer-events: none;
}
.aap-hero h1,
.aap-hero h2,
.aap-hero .hero-headline {
	  color: var(--aap-white) !important;
	  font-size: clamp(2rem, 4vw, 3.25rem) !important;
	  font-weight: 800 !important;
	  line-height: 1.15 !important;
	  max-width: 780px;
}
.aap-hero p,
.aap-hero .hero-sub {
	  color: rgba(255,255,255,0.85) !important;
	  font-size: 1.125rem !important;
	  line-height: 1.75 !important;
	  max-width: 640px;
	  margin-top: 20px;
}
.aap-hero-eyebrow {
	  font-size: 0.8rem !important;
	  font-weight: 700 !important;
	  letter-spacing: 0.12em !important;
	  text-transform: uppercase !important;
	  color: var(--aap-accent) !important;
	  margin-bottom: 20px !important;
	  display: block;
}
.aap-hero-buttons {
	  display: flex;
	  gap: 16px;
	  flex-wrap: wrap;
	  margin-top: 36px;
}
.aap-hero-trust {
	  margin-top: 24px;
	  font-size: 0.8rem !important;
	  color: rgba(255,255,255,0.55) !important;
}

/* ============================================
 *    TRUST BAR
 *    ============================================ */
.aap-trust-bar {
	  background: var(--aap-white) !important;
	  border-bottom: 1px solid var(--aap-gray-100) !important;
	  padding: 28px 0 !important;
	  box-shadow: 0 4px 16px rgba(13,31,60,0.04) !important;
}
.aap-trust-bar-grid {
	  display: grid;
	  grid-template-columns: repeat(4, 1fr);
	  gap: 0;
}
.aap-trust-item {
	  padding: 16px 24px !important;
	  border-right: 1px solid var(--aap-gray-100) !important;
	  text-align: center;
}
.aap-trust-item:last-child { border-right: none !important; }
.aap-trust-number {
	  font-size: 1.75rem !important;
	  font-weight: 800 !important;
	  color: var(--aap-blue) !important;
	  line-height: 1 !important;
	  display: block;
}
.aap-trust-label {
	  font-size: 0.8rem !important;
	  color: var(--aap-gray-600) !important;
	  margin-top: 6px !important;
	  display: block;
}

/* ============================================
 *    TESTIMONIAL CARDS
 *    ============================================ */
.aap-testimonial {
	  background: var(--aap-white) !important;
	  border-radius: var(--aap-radius-lg) !important;
	  box-shadow: var(--aap-shadow) !important;
	  padding: 36px !important;
	  border: 1px solid var(--aap-gray-100) !important;
	  position: relative;
}
.aap-testimonial::before {
	  content: '201C';
	  font-size: 4rem;
	  color: var(--aap-blue);
	  opacity: 0.15;
	  position: absolute;
	  top: 16px;
	  left: 24px;
	  font-family: Georgia, serif;
	  line-height: 1;
}
.aap-testimonial blockquote,
.aap-testimonial .quote-text {
	  font-size: 1rem !important;
	  color: var(--aap-gray-700) !important;
	  font-style: italic !important;
	  line-height: 1.75 !important;
	  margin: 0 0 20px !important;
	  padding-top: 20px;
}
.aap-testimonial .cite-name {
	  font-weight: 700 !important;
	  color: var(--aap-navy) !important;
	  font-size: 0.9rem !important;
}
.aap-testimonial .cite-title {
	  font-size: 0.8rem !important;
	  color: var(--aap-gray-600)
}
}
}
}
}
}
