/* ============================================
 *    AAP DESIGN ENHANCEMENT v3.0
 *    Professional Animations, Depth &amp; Polish
 *    ============================================ */

/* ── ANIMATION KEYFRAMES ─────────────────────── */
@keyframes aap-fade-up {
  from { opacity: 0; transform: translateY(24px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes aap-fade-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}
@keyframes aap-slide-right {
  from { opacity: 0; transform: translateX(-20px); }
  to   { opacity: 1; transform: translateX(0); }
}
@keyframes aap-shimmer {
  0%   { background-position: -200% center; }
  100% { background-position: 200% center; }
}
@keyframes aap-pulse-glow {
  0%, 100% { box-shadow: 0 0 0 0 rgba(26,86,219,0.18); }
  50%       { box-shadow: 0 0 0 8px rgba(26,86,219,0); }
}
@keyframes aap-header-drop {
  from { opacity: 0; transform: translateY(-8px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes aap-border-glow {
  0%, 100% { border-color: rgba(26,86,219,0.3); }
  50%       { border-color: rgba(26,86,219,0.7); }
}

/* ── SCROLL REVEAL (JS-free, CSS-only approach) ── */
.aap-reveal {
  opacity: 0;
  transform: translateY(28px);
  transition: opacity 0.65s cubic-bezier(0.4,0,0.2,1), transform 0.65s cubic-bezier(0.4,0,0.2,1);
}
.aap-reveal.is-visible {
  opacity: 1;
  transform: translateY(0);
}

/* ── ENHANCED HEADER ────────────────────────── */
.aap-global-header {
  background: rgba(255,255,255,0.97) !important;
  backdrop-filter: saturate(1.8) blur(18px) !important;
  -webkit-backdrop-filter: saturate(1.8) blur(18px) !important;
  border-bottom: 1px solid rgba(13,31,60,0.08) !important;
  box-shadow: 0 1px 0 rgba(255,255,255,0.9), 0 4px 20px rgba(13,31,60,0.06), 0 1px 3px rgba(13,31,60,0.04) !important;
  animation: aap-header-drop 0.4s ease both;
  transition: box-shadow 0.3s ease, background 0.3s ease !important;
}
.aap-global-header:hover {
  box-shadow: 0 1px 0 rgba(255,255,255,0.9), 0 8px 32px rgba(13,31,60,0.10), 0 1px 3px rgba(13,31,60,0.06) !important;
}
.aap-global-header.scrolled {
  box-shadow: 0 2px 40px rgba(13,31,60,0.12) !important;
}

/* ── BRAND LOGO ANIMATION ────────────────────── */
.aap-global-brand {
  transition: opacity 0.2s ease, transform 0.2s ease !important;
}
.aap-global-brand:hover {
  opacity: 0.88 !important;
  transform: translateY(-1px) !important;
}
.aap-global-brand img {
  filter: drop-shadow(0 2px 4px rgba(13,31,60,0.12));
  transition: filter 0.3s ease !important;
}
.aap-global-brand:hover img {
  filter: drop-shadow(0 4px 8px rgba(13,31,60,0.18));
}
.aap-global-brand-copy strong {
  background: linear-gradient(135deg, #0d1f3c 0%, #1a56db 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* ── ENHANCED NAV LINKS ──────────────────────── */
.aap-global-nav a {
  position: relative;
  transition: color 0.2s ease, background 0.2s ease !important;
}
.aap-global-nav a::after {
  content: '';
  position: absolute;
  bottom: 4px;
  left: 50%;
  right: 50%;
  height: 2px;
  background: linear-gradient(90deg, #1a56db, #0ea5e9);
  border-radius: 2px;
  transition: left 0.25s ease, right 0.25s ease;
}
.aap-global-nav a:hover::after,
.aap-global-nav a.current::after {
  left: 8px;
  right: 8px;
}
.aap-global-nav a.current {
  color: #1a56db !important;
  font-weight: 700 !important;
}

/* ── CTA BUTTON GLOW ─────────────────────────── */
.aap-global-cta {
  position: relative;
  overflow: hidden;
  animation: aap-pulse-glow 3s ease infinite;
  transition: transform 0.2s ease, box-shadow 0.2s ease !important;
}
.aap-global-cta::before {
  content: '';
  position: absolute;
  top: 0; left: -100%;
  width: 200%;
  height: 100%;
  background: linear-gradient(90deg, transparent 25%, rgba(255,255,255,0.15) 50%, transparent 75%);
  transition: left 0.4s ease;
}
.aap-global-cta:hover::before {
  left: 100%;
}
.aap-global-cta:hover {
  transform: translateY(-2px) scale(1.02) !important;
}

/* ── ENHANCED FOOTER ─────────────────────────── */
.aap-live-footer {
  background: linear-gradient(160deg, #0a1628 0%, #0d1f3c 45%, #111827 100%) !important;
  border-top: 1px solid rgba(26,86,219,0.2) !important;
  position: relative;
  overflow: hidden;
}
.aap-live-footer::before {
  content: '';
  position: absolute;
  top: 0; left: 0;
  width: 100%; height: 3px;
  background: linear-gradient(90deg, #1a56db 0%, #0ea5e9 50%, #0891b2 100%);
}
.aap-live-footer::after {
  content: '';
  position: absolute;
  top: -60%;
  right: -10%;
  width: 500px; height: 500px;
  background: radial-gradient(circle, rgba(26,86,219,0.04) 0%, transparent 70%);
  pointer-events: none;
}

/* Footer headings */
.aap-live-footer h3 {
  position: relative;
  padding-bottom: 10px !important;
  margin-bottom: 18px !important;
}
.aap-live-footer h3::after {
  content: '';
  position: absolute;
  bottom: 0; left: 0;
  width: 28px; height: 2px;
  background: linear-gradient(90deg, #1a56db, #0ea5e9);
  border-radius: 2px;
}

/* Footer links */
.aap-live-footer a {
  transition: color 0.2s ease, padding-left 0.2s ease !important;
  position: relative;
}
.aap-live-footer a:not(.aap-footer-btn):hover {
  color: #93c5fd !important;
  padding-left: 4px !important;
}

/* Footer CTA button */
.aap-footer-btn {
  background: linear-gradient(135deg, #1a56db 0%, #0ea5e9 100%) !important;
  border: 1px solid rgba(255,255,255,0.15) !important;
  box-shadow: 0 4px 16px rgba(26,86,219,0.3), 0 1px 3px rgba(0,0,0,0.15) !important;
  transition: transform 0.2s ease, box-shadow 0.2s ease !important;
}
.aap-footer-btn:hover {
  transform: translateY(-2px) !important;
  box-shadow: 0 8px 24px rgba(26,86,219,0.4), 0 2px 6px rgba(0,0,0,0.2) !important;
}

/* Footer bottom bar */
.aap-live-footer-bottom {
  background: rgba(0,0,0,0.2);
  border-radius: 12px;
  padding: 14px 20px !important;
  margin-top: 28px !important;
}

/* Social links */
.aap-social-links a {
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 8px;
  background: rgba(255,255,255,0.04);
  transition: background 0.2s ease, border-color 0.2s ease, transform 0.2s ease !important;
}
.aap-social-links a:hover {
  background: rgba(26,86,219,0.2) !important;
  border-color: rgba(26,86,219,0.4) !important;
  transform: translateY(-2px) !important;
}

/* ── ENHANCED SECTION SECTIONS ───────────────── */
body.aap-hotfix .aap-live-main .section {
  position: relative;
}
body.aap-hotfix .aap-live-main .section-sky {
  background: linear-gradient(160deg, #f0f7ff 0%, #e8f4fd 100%) !important;
}
body.aap-hotfix .aap-live-main .section-sand {
  background: linear-gradient(160deg, #fffdfb 0%, #fef3e8 100%) !important;
}
body.aap-hotfix .aap-live-main .section-forest {
  background: linear-gradient(160deg, #f8fdf7 0%, #ecf5e8 100%) !important;
}

/* ── ENHANCED HERO SECTION ────────────────────── */
body.aap-hotfix .aap-live-main .hero,
body.aap-hotfix .aap-live-main .aap-service-hero {
  background: linear-gradient(135deg, #f0f7ff 0%, #e8f0fd 60%, #f8f9ff 100%) !important;
  border-bottom: 1px solid rgba(26,86,219,0.08);
  position: relative;
  overflow: hidden;
}
body.aap-hotfix .aap-live-main .hero::before,
body.aap-hotfix .aap-live-main .aap-service-hero::before {
  content: '';
  position: absolute;
  top: -40%;
  right: -5%;
  width: 55%;
  height: 180%;
  background: radial-gradient(ellipse, rgba(26,86,219,0.05) 0%, transparent 70%);
  pointer-events: none;
}

/* Hero heading animation */
body.aap-hotfix .aap-live-main .hero .section-heading h1,
body.aap-hotfix .aap-live-main .aap-service-hero .section-heading h1 {
  animation: aap-fade-up 0.7s cubic-bezier(0.4,0,0.2,1) 0.1s both;
}
body.aap-hotfix .aap-live-main .hero .section-heading p,
body.aap-hotfix .aap-live-main .aap-service-hero .section-heading p,
body.aap-hotfix .aap-live-main .hero .section-heading .lede,
body.aap-hotfix .aap-live-main .aap-service-hero .section-heading .lede {
  animation: aap-fade-up 0.7s cubic-bezier(0.4,0,0.2,1) 0.2s both;
}
